python -c "import json,re; from pathlib import Path; out=Path('.codex/tmp/final-integration-accessors.json'); out.parent.mkdir(parents=True, exist_ok=True); text=Path('.agents/skills/lp-pipeline-orchestrator/references/commands.md').read_text(); keys=['single-regression-check.command','degraded-design-drift-check.command']; resolved={};
for key in keys:
 lines=[ln for ln in text.splitlines() if key in ln];
 assert len(lines)==1, f'{key}: expected exactly 1 candidate line, got {len(lines)}';
 ln=lines[0].strip(); cmd=None;
 if '|' in ln:
  parts=[p.strip() for p in ln.split('|') if p.strip()];
  if parts and parts[0].strip(chr(96))==key and len(parts)>=2:
   cmd=parts[1];
 if cmd is None:
  m=re.search(re.escape(key)+r'\s*[:=]\s*(.+)$', ln);
  if m:
   cmd=m.group(1).strip();
 assert cmd is not None, f'{key}: malformed accessor line: {ln}';
 cmd=cmd.strip(chr(96)).strip();
