 resolved[key]=cmd;
assert len(set(resolved.values()))==2, f'accessors must resolve to two deterministic commands: {resolved}';
out.write_text(json.dumps(resolved, indent=2, sort_keys=True) + '\n');
print('accessors-deterministic-ok', out)"

